def fibonacci(n):
    """Fast doubling Fibonacci - O(log n) time."""
    def _fast_fib(k):
        if k == 0:
            return (0, 1)
        a, b = _fast_fib(k // 2)
        c = a * (b * 2 - a)
        d = a * a + b * b
        if k % 2 == 0:
            return (c, d)
        else:
            return (d, c + d)

    if n < 0:
        raise ValueError("n must be non-negative")
    return _fast_fib(n)[0]

def fibonacci(n):
    if n == 0:
        return 0
    if n == 1:
        return 1
    a, b = 0, 1
    for i in range(2, n + 1):
        a, b = b, a + b
    return b

def fibonacci(n):
    """Matrix exponentiation approach for O(log n) Fibonacci."""
    if n <= 0:
        return 0
    if n == 1:
        return 1

    def multiply(A, B):
        return [
            [A[0][0] * B[0][0] + A[0][1] * B[1][0],
             A[0][0] * B[0][1] + A[0][1] * B[1][1]],
            [A[1][0] * B[0][0] + A[1][1] * B[1][0],
             A[1][0] * B[0][1] + A[1][1] * B[1][1]]
        ]

    def power(matrix, n):
        if n == 1:
            return matrix
        if n % 2 == 0:
            half = power(matrix, n // 2)
            return multiply(half, half)
        else:
            return multiply(matrix, power(matrix, n - 1))

    base = [[1, 1], [1, 0]]
    result = power(base, n)
    return result[0][1]

def fibonacci(n):
    """Iterative solution with manual memoization."""
    if n < 0:
        raise ValueError("Argument must be non-negative")
    if n == 0:
        return 0
    if n == 1:
        return 1

    fib_prev2 = 0
    fib_prev1 = 1
    for _ in range(2, n + 1):
        fib_curr = fib_prev1 + fib_prev2
        fib_prev2 = fib_prev1
        fib_prev1 = fib_curr
    return fib_prev1

def fibonacci(n):
    """Compute Fibonacci using fast doubling (iterative)."""
    if n < 0:
        raise ValueError("Negative input")
    a, b = 0, 1
    bits = []
    k = n
    while k > 0:
        bits.append(k & 1)
        k >>= 1
    for bit in reversed(bits):
        c = a * (2 * b - a)
        d = a * a + b * b
        if bit:
            a, b = d, c + d
        else:
            a, b = c, d
    return a

def fibonacci(n):
    if n <= 0:
        return 0
    if n == 1:
        return 1
    table = [0, 1]
    for i in range(2, n + 1):
        table.append(table[i-1] + table[i-2])
    return table[n]
